// Pokémon data for grid categories and answer validation
// Loads from pokemon-data.json (generated by `npm run fetch-pokemon`) if available,
// otherwise falls back to a curated built-in set.

import type { CategoryType, Category, Pokemon } from "./types";

export type { CategoryType, Category, Pokemon };

// Try to load the full PokéAPI-sourced dataset
let pokemonData: Pokemon[];
try {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  pokemonData = require("./pokemon-data.json") as Pokemon[];
  console.log(`Loaded ${pokemonData.length} Pokémon from PokéAPI dataset`);
} catch {
  // Fall back to curated built-in data
  pokemonData = require("./pokemon-fallback").FALLBACK_POKEMON as Pokemon[];
  console.log(`Using fallback dataset (${pokemonData.length} Pokémon). Run "npm run fetch-pokemon" for the full set.`);
}

