// Map from egg group category ID suffix to the egg group names used in PokéAPI data
const EGG_GROUP_MAP: Record<string, string[]> = {
  monster: ["monster"],
  water1: ["water1"],
  water2: ["water2"],
  water3: ["water3"],
  bug: ["bug"],
  flying: ["flying"],
  field: ["field"],
  fairy: ["fairy"],
  grass: ["grass", "plant"],
  humanlike: ["humanlike", "human-like", "humanshape"],
  mineral: ["mineral"],
  amorphous: ["amorphous", "indeterminate"],
  ditto: ["ditto"],
  dragon: ["dragon"],
  undiscovered: ["undiscovered", "no-eggs"],
};

// Check if a Pokémon matches a given category
export function pokemonMatchesCategory(pokemon: Pokemon, categoryId: string): boolean {
  const dashIdx = categoryId.indexOf("-");
  const group = categoryId.substring(0, dashIdx);
  const value = categoryId.substring(dashIdx + 1);

  switch (group) {
    case "type":
      return pokemon.types.includes(value);
    case "gen":
      return pokemon.generation === parseInt(value);
    case "egg": {
      const validNames = EGG_GROUP_MAP[value] || [value];
      return pokemon.eggGroups.some(eg =>
        validNames.some(valid => eg.toLowerCase().replace(/[- ]/g, "") === valid.toLowerCase().replace(/[- ]/g, ""))
      );
    }
    case "evo":
      return pokemon.evolutionMethod.includes(value);
    case "status":
      return pokemon.status.includes(value);
    default:
      return false;
  }
}

// Find a Pokémon by name (case-insensitive)
export function findPokemon(name: string): Pokemon | undefined {
  return POKEMON.find(p => p.name.toLowerCase() === name.toLowerCase());
}

// Get all Pokémon matching a category
export function getPokemonForCategory(categoryId: string): Pokemon[] {
  return POKEMON.filter(p => pokemonMatchesCategory(p, categoryId));
}

// Check if any Pokémon can satisfy both categories (for grid validation)
export function hasValidAnswer(rowCategoryId: string, colCategoryId: string): boolean {
  return POKEMON.some(p =>
    pokemonMatchesCategory(p, rowCategoryId) && pokemonMatchesCategory(p, colCategoryId)
  );
}

// Get all Pokémon names for autocomplete
export function getAllPokemonNames(): string[] {
  return POKEMON.map(p => p.name).sort();
}

// Get Pokémon names filtered by both row and column category (for Create/Edit grid cells)
export function getFilteredPokemonNames(rowCategoryId?: string, colCategoryId?: string, exclude?: Set<string>): string[] {
  let filtered = POKEMON;
  if (rowCategoryId) {
    filtered = filtered.filter(p => pokemonMatchesCategory(p, rowCategoryId));
  }
  if (colCategoryId) {
    filtered = filtered.filter(p => pokemonMatchesCategory(p, colCategoryId));
  }
  let names = filtered.map(p => p.name).sort();
  if (exclude && exclude.size > 0) {
    names = names.filter(n => !exclude.has(n));
  }
  return names;
}

// Get sprite URL for a Pokémon (uses PokéAPI sprites)
export function getPokemonSpriteUrl(name: string): string | null {
  const pokemon = findPokemon(name);
  if (!pokemon) return null;
  return `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${pokemon.dexNumber}.png`;
}
